// src/api/followApi.js
import axios from "axios";
import { API_BASE_URL } from "../config/config";

const API_URL = `${API_BASE_URL}api/user/follow`;

// Helper function to get token from localStorage
const getAuthToken = () => {
  const token = localStorage.getItem("access_token");
  return token ? `Bearer ${token}` : "";
};
const getStoredUserData = () => {
  // Try Signatory first
  let signatoryData = localStorage.getItem("SignatoryLoginData");
  if (signatoryData) {
    const userData = JSON.parse(signatoryData);
    return {
      userData: userData,
      loginType: "signatory",
      access_token: userData?.access_token || userData?.token,
    };
  }

  // Try generic InvestorData
  let investorData = localStorage.getItem("InvestorData");
  if (investorData) {
    const userData = JSON.parse(investorData);
    return {
      userData: userData,
      loginType: "investor",
      access_token: userData?.access_token || userData?.token,
    };
  }

  return null;
};

// Use it
const userInfo = getStoredUserData();
const token = userInfo?.access_token;
// Helper function to get headers
const getHeaders = () => {
  return {
    headers: {
      Authorization: getAuthToken(),
      "Content-Type": "application/json",
      Authorization: `Bearer ${token}`,
    },
  };
};

export const followUser = async (
  follower_id,
  follower_type,
  following_id,
  following_type,
) => {
  const res = await axios.post(
    `${API_URL}/follow`,
    {
      follower_id,
      follower_type,
      following_id,
      following_type,
    },
    getHeaders(), // ✅ Add headers
  );
  return res.data;
};

